                               max_retries=3, retry_delay=65, label="Agent"):
    """Call client.messages.create with linear backoff on RateLimitError."""
    if os.environ.get("TMM_USE_OLLAMA") == "1":
        import requests

        ollama_messages = []
        if system:
            ollama_messages.append({"role": "system", "content": system})
        for msg in messages:
            ollama_messages.append(msg)

        payload = {
            "model": "qwen2.5:14b",
            "messages": ollama_messages,
            "stream": False,
            "options": {
                "temperature": 0.2
            }
        }

        # Call local Ollama
        try:
            resp = requests.post("http://localhost:11434/api/chat", json=payload, timeout=300)
            resp.raise_for_status()
            result_text = resp.json()["message"]["content"]
        except Exception as e:
            print(f"[{label}] Ollama error: {e}")
            raise

        class MockContent:
            def __init__(self, text):
                self.text = text

        class MockResponse:
            def __init__(self, text):
                self.content = [MockContent(text)]

        return MockResponse(result_text)

    for attempt in range(max_retries):"

