/**
 * Margaret's Interactive Collaborative Dashboard
 * Enables Tom to track daily patterns, read Margaret's elephant-coded lab notebook,
 * and submit direct market observations back into Margaret's cognitive cycle.
 */

// Paths
$tom_feedback_file = __DIR__ . '/tom_feedback.json';
$margaret_log_file = __DIR__ . '/../public-data/governance-margaret.json'; // TMM relative
if (!file_exists($margaret_log_file)) {
    $margaret_log_file = __DIR__ . '/../../TMM/public-data/governance-margaret.json'; // newmarketmonkey relative
}
if (!file_exists($margaret_log_file)) {
    $margaret_log_file = 'Y:/trainedmarketmonkey/TMM/public-data/governance-margaret.json'; // Windows local absolute
}
$history_file = __DIR__ . '/margaret_patterns_history.json';

// Handle Feedback Form Submission (POST)
$feedback_submitted = false;
$error_msg = '';
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['tom_thought'])) {
    $thought = trim($_POST['tom_thought']);
    if (!empty($thought)) {
        // Read existing feedback
        $feedback_list = [];
        if (file_exists($tom_feedback_file)) {
            $raw = file_get_contents($tom_feedback_file);
            $feedback_list = json_decode($raw, true) ?? [];
        }

        // Append new feedback entry
        $new_entry = [
            'timestamp' => date('Y-m-d H:i:s'),
            'thought' => $thought
        ];
        // Prepend so latest is first
        array_unshift($feedback_list, $new_entry);

        // Keep last 30 entries
        if (count($feedback_list) > 30) {
            $feedback_list = array_slice($feedback_list, 0, 30);
        }

        // Save atomically
        if (file_put_contents($tom_feedback_file, json_encode($feedback_list, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE)) !== false) {
            $feedback_submitted = true;
        } else {
            $error_msg = 'Failed to write feedback to disk. Please check folder permissions.';
        }
    }
}

