sys.stdout.reconfigure(encoding='utf-8')
agents = glob.glob('agents/*.py')
for f in sorted(agents):
    if '__init__' in f or 'base_' in f: continue
    with open(f, 'r', encoding='utf-8') as file:
        try:
            tree = ast.parse(file.read())
        except Exception as e:
            print('ERROR PARSING:', f, e)
            continue
        class_node = None
        for node in tree.body:
            if isinstance(node, ast.ClassDef):
                class_node = node
                break
        if not class_node: continue

        name = ''
        persona = ''
        focus = ''
        for item in class_node.body:
            if isinstance(item, ast.Assign):
                for target in item.targets:
                    if isinstance(target, ast.Name):
                        if target.id == 'name':
                            name = ast.literal_eval(item.value)
                        elif target.id == 'persona':
                            persona = ast.literal_eval(item.value)
                        elif target.id == 'focus':
                            focus = ast.literal_eval(item.value)
        doc = ast.get_docstring(class_node) or ''
        print('=== FILE:', f)
        print('Class:', class_node.name)
        print('Name:', name or class_node.name)
        print('Doc:', doc.strip().split('\n')[0] if doc else '')
        print('Focus:', focus)
        print('Persona:', persona.strip()[:300] + '...' if persona else '')
        print()
